import React, { useState } from 'react';
import { ImageOff, Loader2 } from 'lucide-react';

interface OptimizedImageProps {
  src: string;
  alt: string;
  className?: string;
  containerClassName?: string;
  objectFit?: 'cover' | 'contain' | 'fill';
  aspectRatio?: string;
}

const OptimizedImage: React.FC<OptimizedImageProps> = ({ 
  src, 
  alt, 
  className = '', 
  containerClassName = '',
  objectFit = 'cover',
  aspectRatio
}) => {
  const [isLoaded, setIsLoaded] = useState(false);
  const [hasError, setHasError] = useState(false);

  return (
    <div 
      className={`relative overflow-hidden bg-slate-100 ${containerClassName}`}
      style={aspectRatio ? { aspectRatio } : undefined}
    >
      {/* Loading Placeholder */}
      {!isLoaded && !hasError && (
        <div className="absolute inset-0 flex items-center justify-center z-10">
          <div className="absolute inset-0 bg-slate-100 animate-pulse"></div>
          <Loader2 className="w-8 h-8 text-primary/30 animate-spin relative z-20" />
        </div>
      )}

      {/* Error State */}
      {hasError ? (
        <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-400 bg-slate-50 p-6 text-center border border-slate-100">
          <ImageOff className="w-10 h-10 mb-3 opacity-20" />
          <span className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400">Media Unavailable</span>
        </div>
      ) : (
        <img
          src={src}
          alt={alt}
          onLoad={() => setIsLoaded(true)}
          onError={() => setHasError(true)}
          loading="lazy"
          className={`
            w-full h-full transition-all duration-1000 ease-out
            ${objectFit === 'cover' ? 'object-cover' : objectFit === 'contain' ? 'object-contain' : 'object-fill'}
            ${isLoaded ? 'opacity-100 scale-100 blur-0' : 'opacity-0 scale-110 blur-xl'}
            ${className}
          `}
        />
      )}
    </div>
  );
};

export default OptimizedImage;

